  1	import {
  2	  AlertStates,
  3	  ListPageFilter,
  4	  PrometheusAlert,
  5	  RowFilter,
  6	  RowProps,
  7	  Rule,
  8	  TableColumn,
  9	  useListPageFilter,
 10	  VirtualizedTable,
 11	} from '@openshift-console/dynamic-plugin-sdk';
 12	import { sortable, Td } from '@patternfly/react-table';
 13	import * as _ from 'lodash-es';
 14	import * as React from 'react';
 15	import { Helmet } from 'react-helmet';
 16	import { useTranslation } from 'react-i18next';
 17	import { useSelector } from 'react-redux';
 18	import { Link } from 'react-router-dom';
 19	
 20	import { Alerts, AlertSource } from '../types';
 21	import {
 22	  alertingRuleStateOrder,
 23	  alertSeverityOrder,
 24	  fuzzyCaseInsensitive,
 25	  RuleResource,
 26	} from '../utils';
 27	
 28	import { getLegacyObserveState, getRuleUrl, usePerspective } from '../hooks/usePerspective';
 29	import {
 30	  alertingRuleSource,
 31	  AlertStateIcon,
 32	  getAdditionalSources,
 33	  getAlertStateKey,
 34	  MonitoringResourceIcon,
 35	  Severity,
 36	  SilencesNotLoadedWarning,
 37	} from '../alerting/AlertUtils';
 38	import { MonitoringState } from '../../reducers/observe';
 39	import { severityRowFilter } from './AlertUtils';
 40	import { EmptyBox } from '../console/console-shared/src/components/empty-state/EmptyBox';
 41	import withFallback from '../console/console-shared/error/fallbacks/withFallback';
 42	import { Flex, FlexItem, PageSection, PageSectionVariants } from '@patternfly/react-core';
 43	
 44	const StateCounts: React.FC<{ alerts: PrometheusAlert[] }> = ({ alerts }) => {
 45	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 46	
 47	  const counts = _.countBy(alerts, 'state');
 48	  const states = [AlertStates.Firing, AlertStates.Pending, AlertStates.Silenced].filter(
 49	    (s) => counts[s] > 0,
 50	  );
 51	
 52	  return (
 53	    <>
 54	      {states.map((s) => (
 55	        <div className="monitoring-icon-wrap" key={s}>
 56	          <AlertStateIcon state={s} /> {counts[s]} {getAlertStateKey(s, t)}
 57	        </div>
 58	      ))}
 59	    </>
 60	  );
 61	};
 62	
 63	const ruleHasAlertState = (rule: Rule, state: AlertStates): boolean =>
 64	  state === AlertStates.NotFiring ? _.isEmpty(rule.alerts) : _.some(rule.alerts, { state });
 65	
 66	const ruleAlertStateFilter = (filter, rule: Rule) =>
 67	  (filter.selected?.includes(AlertStates.NotFiring) && _.isEmpty(rule.alerts)) ||
 68	  _.some(rule.alerts, (a) => filter.selected?.includes(a.state)) ||
 69	  _.isEmpty(filter.selected);
 70	
 71	const alertStateFilter = (t): RowFilter => ({
 72	  filter: ruleAlertStateFilter,
 73	  filterGroupName: t('Alert State'),
 74	  isMatch: ruleHasAlertState,
 75	  items: [
 76	    { id: AlertStates.Firing, title: t('Firing') },
 77	    { id: AlertStates.Pending, title: t('Pending') },
 78	    { id: AlertStates.Silenced, title: t('Silenced') },
 79	    { id: AlertStates.NotFiring, title: t('Not Firing') },
 80	  ],
 81	  type: 'alerting-rule-has-alert-state',
 82	});
 83	
 84	const tableRuleClasses = [
 85	  'pf-v6-u-w-50 pf-u-w-33-on-sm', // Name
 86	  'pf-m-hidden pf-m-visible-on-sm', // Severity
 87	  '', // Alert state
 88	  'pf-m-hidden pf-m-visible-on-sm', // Source
 89	];
 90	
 91	const RuleTableRow: React.FC<RowProps<Rule>> = ({ obj }) => {
 92	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 93	  const { perspective } = usePerspective();
 94	
 95	  const title: string = obj.annotations?.description || obj.annotations?.message;
 96	
 97	  return (
 98	    <>
 99	      <Td className={tableRuleClasses[0]} title={title}>
100	        <Flex spaceItems={{ default: 'spaceItemsNone' }} flexWrap={{ default: 'nowrap' }}>
101	          <FlexItem>
102	            <MonitoringResourceIcon resource={RuleResource} />
103	          </FlexItem>
104	          <FlexItem>
105	            <Link to={getRuleUrl(perspective, obj)} className="pf-v6-u-text-break-word">
106	              {obj.name}
107	            </Link>
108	          </FlexItem>
109	        </Flex>
110	      </Td>
111	      <Td className={tableRuleClasses[1]} title={title}>
112	        <Severity severity={obj.labels?.severity} />
113	      </Td>
114	      <Td className={tableRuleClasses[2]} title={title}>
115	        {_.isEmpty(obj.alerts) ? '-' : <StateCounts alerts={obj.alerts} />}
116	      </Td>
117	      <Td className={tableRuleClasses[3]} title={title}>
118	        {alertingRuleSource(obj) === AlertSource.User ? t('User') : t('Platform')}
119	      </Td>
120	    </>
121	  );
122	};
123	
124	const AlertRulesPage_: React.FC = () => {
125	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
126	  const { alertsKey, silencesKey, rulesKey, perspective, defaultAlertTenant } = usePerspective();
127	
128	  const data: Rule[] = useSelector((state: MonitoringState) =>
129	    getLegacyObserveState(perspective, state)?.get(rulesKey),
130	  );
131	  const { loaded = false, loadError }: Alerts = useSelector(
132	    (state: MonitoringState) => getLegacyObserveState(perspective, state)?.get(alertsKey) || {},
133	  );
134	  const silencesLoadError = useSelector(
135	    (state: MonitoringState) =>
136	      getLegacyObserveState(perspective, state)?.get(silencesKey)?.loadError,
137	  );
138	
139	  const ruleAdditionalSources = React.useMemo(
140	    () => getAdditionalSources(data, alertingRuleSource),
141	    [data],
142	  );
143	
144	  const rowFilters: RowFilter[] = [
145	    // TODO: The "name" filter doesn't really fit useListPageFilter's idea of a RowFilter, but
146	    //       useListPageFilter doesn't yet provide a better way to add a filter like this
147	    {
148	      filter: (filter, rule: Rule) => fuzzyCaseInsensitive(filter.selected?.[0], rule.name),
149	      filterGroupName: '',
150	      items: [],
151	      type: 'name',
152	    } as RowFilter,
153	    alertStateFilter(t),
154	    severityRowFilter(t),
155	    {
156	      defaultSelected: defaultAlertTenant,
157	      filter: (filter, rule: Rule) =>
158	        filter.selected?.includes(alertingRuleSource(rule)) || _.isEmpty(filter.selected),
159	      filterGroupName: t('Source'),
160	      items: [
161	        { id: AlertSource.Platform, title: t('Platform') },
162	        { id: AlertSource.User, title: t('User') },
163	        ...ruleAdditionalSources,
164	      ],
165	      reducer: alertingRuleSource,
166	      type: 'alerting-rule-source',
167	    },
168	  ];
169	
170	  const [staticData, filteredData, onFilterChange] = useListPageFilter(data, rowFilters);
171	
172	  const columns = React.useMemo<TableColumn<Rule>[]>(
173	    () => [
174	      {
175	        id: 'name',
176	        props: { className: tableRuleClasses[0] },
177	        sort: 'name',
178	        title: t('Name'),
179	        transforms: [sortable],
180	      },
181	      {
182	        id: 'severity',
183	        props: { className: tableRuleClasses[1] },
184	        sort: (rules: Rule[], direction: 'asc' | 'desc') =>
185	          _.orderBy(rules, alertSeverityOrder, [direction]) as Rule[],
186	        title: t('Severity'),
187	        transforms: [sortable],
188	      },
189	      {
190	        id: 'state',
191	        props: { className: tableRuleClasses[2] },
192	        sort: (rules: Rule[], direction: 'asc' | 'desc') =>
193	          _.orderBy(rules, alertingRuleStateOrder, [direction]),
194	        title: t('Alert state'),
195	        transforms: [sortable],
196	      },
197	      {
198	        id: 'source',
199	        props: { className: tableRuleClasses[3] },
200	        sort: (rules: Rule[], direction: 'asc' | 'desc') =>
201	          _.orderBy(rules, alertingRuleSource, [direction]),
202	        title: t('Source'),
203	        transforms: [sortable],
204	      },
205	    ],
206	    [t],
207	  );
208	
209	  return (
210	    <>
211	      <Helmet>
212	        <title>Alerting</title>
213	      </Helmet>
214	      <PageSection variant={PageSectionVariants.light}>
215	        <ListPageFilter
216	          data={staticData}
217	          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
218	          // @ts-ignore TODO
219	          labelFilter="observe-rules"
220	          labelPath="labels"
221	          loaded={loaded}
222	          onFilterChange={onFilterChange}
223	          rowFilters={rowFilters}
224	        />
225	        {silencesLoadError && <SilencesNotLoadedWarning silencesLoadError={silencesLoadError} />}
226	        <VirtualizedTable<Rule>
227	          aria-label={t('Alerting rules')}
228	          label={t('Alerting rules')}
229	          columns={columns}
230	          data={filteredData ?? []}
231	          loaded={loaded}
232	          loadError={loadError}
233	          Row={RuleTableRow}
234	          unfilteredData={data}
235	          NoDataEmptyMsg={() => {
236	            return <EmptyBox label={t('Alerting rules')} />;
237	          }}
238	        />
239	      </PageSection>
240	    </>
241	  );
242	};
243	const AlertRulesPage = withFallback(AlertRulesPage_);
244	
245	export default AlertRulesPage;

